def omega_distance(n, m, primes):
    # Simulate Omega distance (product of p-adic distances)
    # For natural numbers embedded diagonally
    distances = []

    # ℚ component
    distances.append(abs(n - m))

    # p-adic components
    for p in primes:
        d = padic_norm(n - m, p)
        distances.append(d)

    return max(distances)

